import {reactive, watch} from "vue"
import WalletConnect from "@walletconnect/client"
import QRCodeModal from "@walletconnect/qrcode-modal"
import Web3 from "web3";
import abiDecoder from 'abi-decoder';

const towersCityABI = require("./abi/TheTowersCity.json");
const tokenABI = require("./abi/Token.json");
const airdropABI = require("./abi/Airdrop.json");

export const PROVIDER_WC = "walletconnect";
export const PROVIDER_MM = "metamask";

abiDecoder.addABI(towersCityABI)
abiDecoder.addABI(tokenABI)
// abiDecoder.discardNonDecodedLogs()

// Create a connector
const walletConnect = new WalletConnect({
    bridge: "https://bridge.walletconnect.org", // Required
    qrcodeModal: QRCodeModal,
});

export const web3 = new Web3(process.env.VUE_APP_EVM_NODE);
export const toBN = web3.utils.toBN
export const toWei = web3.utils.toWei
export const fromWei = web3.utils.fromWei

let Contract = require('web3-eth-contract');
Contract.setProvider(process.env.VUE_APP_EVM_NODE);

let contract = new Contract(towersCityABI, process.env.VUE_APP_TOWERS_CITY_CONTRACT);

export let airdropContract = new web3.eth.Contract(airdropABI, "0xfaa46D64f71987895F11632C18a955d2cB062b0f");

export const state = reactive({
    abiDecoder: abiDecoder,
    web3: web3,
    contract: contract,
    loggedIn: false,
    account: "",
    referrerAddress: "",
    profile: {},
    globalLoader: 0,
    title: "",
    token: {
        name: "SHEKEL",
        address: "",
    },
    currentProvider: "",
    sendTx: function (tx) {
        switch (this.currentProvider) {
            case PROVIDER_WC:
                return walletConnect.sendTransaction(tx)
            case PROVIDER_MM:
                return window.ethereum.request({
                        method: 'eth_sendTransaction',
                        params: [tx],
                    })
            default:
                throw new Error("unknown provider")
        }
    },
    isLoggedIn() {
        return this.loggedIn
    },
    login(provider) {
        switch (provider) {
            case PROVIDER_WC:
                walletConnect.createSession({chainId: 56});
                break
            case PROVIDER_MM:
                window.ethereum.request({ method: 'eth_requestAccounts' })
                    .then((accounts) => {
                        state.loggedIn = true
                        state.account = accounts[0]
                        this.currentProvider = provider
                    }).catch((err) => {
                        console.error(err)
                    });
                break
        }
    },
    logout() {
        switch (this.currentProvider) {
            case PROVIDER_WC:
                walletConnect.killSession()
                break
            case PROVIDER_MM:
                state.loggedIn = false
                state.account = ""
                break
        }

        this.currentProvider = ""
    }
})

export let tokenContract;

state.contract.methods.token().call().then((tokenAddress) => {
    state.token.address = tokenAddress;
    tokenContract = new state.web3.eth.Contract(tokenABI, state.token.address);
})

if (walletConnect.connected) {
    state.loggedIn = true
    state.account = walletConnect.accounts[0]
}

walletConnect.on("connect", (error, payload) => {
    if (error) {
        throw error;
    }

    // Get provided accounts and chainId
    const { accounts, chainId } = payload.params[0];
    console.log(accounts, chainId)
    state.loggedIn = true
    state.account = accounts[0]
    state.currentProvider = PROVIDER_WC
});

walletConnect.on("session_update", (error, payload) => {
    if (error) {
        throw error;
    }

    // Get updated accounts and chainId
    const { accounts, chainId } = payload.params[0];
    console.log(accounts, chainId)

    state.loggedIn = true
    state.account = accounts[0]
    state.currentProvider = PROVIDER_WC
});

walletConnect.on("disconnect", (error) => {
    if (error) {
        throw error;
    }

    state.loggedIn = false
    state.account = ""
    state.currentProvider = ""
});

let provider = localStorage.getItem("currentProvider")
if (provider) {
    state.currentProvider = provider
    state.login(provider)
}

let referrer = localStorage.getItem("referrerAddress")
if (referrer) {
    state.referrerAddress = referrer
}

watch(() => state.currentProvider, () => {
    localStorage.setItem("currentProvider", state.currentProvider)
})

watch(() => state.referrerAddress, () => {
  localStorage.setItem("referrerAddress", state.referrerAddress)
})